import{D as e,f as t,u as n}from"./chunks/runtime-core.esm-bundler.DKQjezWN.js";import{t as r}from"./chunks/plugin-vue_export-helper.Bz49raAe.js";const i=JSON.parse(`{"title":"What is ?","description":"is a static site generator designed for building fast, content-centric websites powered by Vite and Vue.","frontmatter":{"description":"is a static site generator designed for building fast, content-centric websites powered by Vite and Vue.","head":[["meta",{"property":"og:url","content":"https://anhhducnguyen.github.io/docs-v1/guide/what-is-vitepress"}],["meta",{"property":"og:title","content":"What is ?"}],["meta",{"property":"og:description","content":"is a static site generator designed for building fast, content-centric websites powered by Vite and Vue."}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:site_name","content":""}],["meta",{"property":"og:image","content":"https://anhhducnguyen.github.io/docs-v1/vitepress-og.jpg"}],["meta",{"property":"og:image:secure_url","content":"https://anhhducnguyen.github.io/docs-v1/vitepress-og.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1280"}],["meta",{"property":"og:image:height","content":"640"}],["meta",{"property":"og:image:alt","content":""}],["link",{"rel":"canonical","href":"https://anhhducnguyen.github.io/docs-v1/guide/what-is-vitepress"}]]},"headers":[],"relativePath":"guide/what-is-vitepress.md","filePath":"en/guide/what-is-vitepress.md","lastUpdated":1775812879000}`);var a={name:`guide/what-is-vitepress.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /docs-v1/guide/what-is-vitepress.md for this page in Markdown format</div><h1 id="what-is" tabindex="-1">What is ? <a class="header-anchor" href="#what-is" aria-label="Permalink to “What is ?”">​</a></h1><p>is a <a href="https://en.wikipedia.org/wiki/Static_site_generator" target="_blank" rel="noreferrer">Static Site Generator</a> (SSG) designed for building fast, content-centric websites. In a nutshell, takes your source content written in <a href="https://en.wikipedia.org/wiki/Markdown" target="_blank" rel="noreferrer">Markdown</a>, applies a theme to it, and generates static HTML pages that can be easily deployed anywhere.</p><div class="tip custom-block" style="padding-top:8px;"><p>Just want to try it out? Skip to the <a href="./getting-started.html">Quickstart</a>.</p></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use Cases”">​</a></h2><ul><li><p><strong>Documentation</strong></p><p>ships with a default theme designed for technical documentation. It powers this page you are reading right now, along with the documentation for <a href="https://vitejs.dev/" target="_blank" rel="noreferrer">Vite</a>, <a href="https://rollupjs.org/" target="_blank" rel="noreferrer">Rollup</a>, <a href="https://pinia.vuejs.org/" target="_blank" rel="noreferrer">Pinia</a>, <a href="https://vueuse.org/" target="_blank" rel="noreferrer">VueUse</a>, <a href="https://vitest.dev/" target="_blank" rel="noreferrer">Vitest</a>, <a href="https://d3js.org/" target="_blank" rel="noreferrer">D3</a>, <a href="https://unocss.dev/" target="_blank" rel="noreferrer">UnoCSS</a>, <a href="https://iconify.design/" target="_blank" rel="noreferrer">Iconify</a> and <a href="https://github.com/search?q=/%22vitepress%22:+/+path:/(?:package%7Cdeno)%5C.jsonc?$/+NOT+is:fork+NOT+is:archived&amp;type=code" target="_blank" rel="noreferrer">many more</a>.</p><p>The <a href="https://vuejs.org/" target="_blank" rel="noreferrer">official Vue.js documentation</a> is also based on , but uses a custom theme shared between multiple translations.</p></li><li><p><strong>Blogs, Portfolios, and Marketing Sites</strong></p><p>supports <a href="./custom-theme.html">fully customized themes</a>, with the developer experience of a standard Vite + Vue application. Being built on Vite also means you can directly leverage Vite plugins from its rich ecosystem. In addition, provides flexible APIs to <a href="./data-loading.html">load data</a> (local or remote) and <a href="./routing.html#dynamic-routes">dynamically generate routes</a>. You can use it to build almost anything as long as the data can be determined at build time.</p><p>The official <a href="https://blog.vuejs.org/" target="_blank" rel="noreferrer">Vue.js blog</a> is a simple blog that generates its index page based on local content.</p></li></ul><h2 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to “Developer Experience”">​</a></h2><p>aims to provide a great Developer Experience (DX) when working with Markdown content.</p><ul><li><p><strong><a href="https://vitejs.dev/" target="_blank" rel="noreferrer">Vite-Powered:</a></strong> instant server start, with edits always instantly reflected (&lt;100ms) without page reload.</p></li><li><p><strong><a href="./markdown.html">Built-in Markdown Extensions:</a></strong> Frontmatter, tables, syntax highlighting... you name it. Specifically, provides many advanced features for working with code blocks, making it ideal for highly technical documentation.</p></li><li><p><strong><a href="./using-vue.html">Vue-Enhanced Markdown:</a></strong> each Markdown page is also a Vue <a href="https://vuejs.org/guide/scaling-up/sfc.html" target="_blank" rel="noreferrer">Single-File Component</a>, thanks to Vue template&#39;s 100% syntax compatibility with HTML. You can embed interactivity in your static content using Vue templating features or imported Vue components.</p></li></ul><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to “Performance”">​</a></h2><p>Unlike many traditional SSGs where each navigation results in a full page reload, a website generated by serves static HTML on the initial visit, but becomes a <a href="https://en.wikipedia.org/wiki/Single-page_application" target="_blank" rel="noreferrer">Single Page Application</a> (SPA) for subsequent navigation within the site. This model, in our opinion, provides an optimal balance for performance:</p><ul><li><p><strong>Fast Initial Load</strong></p><p>The initial visit to any page will be served the static, pre-rendered HTML for fast loading speed and optimal SEO. The page then loads a JavaScript bundle that turns the page into a Vue SPA (&quot;hydration&quot;). Contrary to common assumptions of SPA hydration being slow, this process is actually extremely fast thanks to Vue 3&#39;s raw performance and compiler optimizations. On <a href="https://pagespeed.web.dev/report?url=https%3A%2F%2Fvitepress.dev%2F" target="_blank" rel="noreferrer">PageSpeed Insights</a>, typical sites achieve near-perfect performance scores even on low-end mobile devices with a slow network.</p></li><li><p><strong>Fast Post-load Navigation</strong></p><p>More importantly, the SPA model leads to better user experience <strong>after</strong> the initial load. Subsequent navigation within the site will no longer cause a full page reload. Instead, the incoming page&#39;s content will be fetched and dynamically updated. also automatically pre-fetches page chunks for links that are within viewport. In most cases, post-load navigation will feel instant.</p></li><li><p><strong>Interactivity Without Penalty</strong></p><p>To be able to hydrate the dynamic Vue parts embedded inside static Markdown, each Markdown page is processed as a Vue component and compiled into JavaScript. This may sound inefficient, but the Vue compiler is smart enough to separate the static and dynamic parts, minimizing both the hydration cost and payload size. For the initial page load, the static parts are automatically eliminated from the JavaScript payload and skipped during hydration.</p></li></ul><h2 id="what-about-vuepress" tabindex="-1">What About VuePress? <a class="header-anchor" href="#what-about-vuepress" aria-label="Permalink to “What About VuePress?”">​</a></h2><p>is the spiritual successor of VuePress 1. The original VuePress 1 was based on Vue 2 and webpack. With Vue 3 and Vite under the hood, provides significantly better DX, better production performance, a more polished default theme, and a more flexible customization API.</p><p>The API difference between and VuePress 1 mostly lies in theming and customization. If you are using VuePress 1 with the default theme, it should be relatively straightforward to migrate to .</p><p>Maintaining two SSGs in parallel isn&#39;t sustainable, so the Vue team has decided to focus on as the main recommended SSG in the long run. Now VuePress 1 has been deprecated, and VuePress 2 has been handed over to the VuePress community team for further development and maintenance.</p>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};